var seed = GetInt(parameters, "seed", context.Seed);
var color = GetColor(parameters, "color", System.Windows.Media.Color.FromRgb(80, 200, 60));
var highlightColor = GetColor(parameters, "highlightColor", System.Windows.Media.Color.FromRgb(200, 255, 160));
var viscosity = GetFloat(parameters, "viscosity", 0.5f);
var bubbles = GetFloat(parameters, "bubbles", 0.5f);
var scale = GetFloat(parameters, "scale", 1.5f);
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var cR=color.R/255f; var cG=color.G/255f; var cB=color.B/255f;
var hR=highlightColor.R/255f; var hG=highlightColor.G/255f; var hB=highlightColor.B/255f;
var period = Math.Max(1, (int)(size * scale));
result.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size * scale;
    var v = y / (float)size * scale;
    var (pu, pv) = PerturbUv(u, v, viscosity * 0.25f, period, seed);
    TileableVoronoi(pu * size / scale, pv * size / scale, Math.Max(1,(int)(size/scale/4)), 4, seed, out var near, out _, out _, out _);
    var bub = Math.Clamp(1f - near / (bubbles * 0.5f + 0.01f), 0f, 1f);
    var base2 = TileableFractalNoise(pu, pv, period, 3, 0.5f, 2f, seed + 7) * 0.7f + 0.3f;
    var t = bub * bub;
    var r = Lerp(cR * base2, hR, t);
    var g = Lerp(cG * base2, hG, t);
    var b2 = Lerp(cB * base2, hB, t);
    result.SetPixel(x, y, r, g, b2, 1f);
});
return result;
